public static long solve(long[] nums) {
    int maxIndex = nums.length - 1;
    boolean[] isPrime = new boolean[maxIndex + 1];
    if (maxIndex >= 2) {
        for (int i = 0; i <= maxIndex; i++) {
            isPrime[i] = true;
        }
        isPrime[0] = false;
        isPrime[1] = false;
        for (int i = 2; i * i <= maxIndex; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= maxIndex; j += i) {
                    isPrime[j] = false;
                }
            }
        }
    }
    long sumA = 0;
    long sumB = 0;
    for (int i = 0; i < nums.length; i++) {
        if (isPrime[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }
    return Math.abs(sumA - sumB);
}
